UPDATE public.questions SET
  stimulus_text = 'A new study shows that people who spend more time in nature report feeling happier and more creative. In fact, spending time in green spaces can help reduce stress and anxiety. However, some experts argue that these benefits are exaggerated, and that the true source of happiness and creativity might be found in other activities, such as spending time with friends and family, or engaging in creative pursuits.',
