UPDATE public.questions SET
  stimulus_text = NULL,
  question_text = 'Which choice correctly punctuates the following sentence? The company decided, to invest in a new product line: a decision that would require significant capital.',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The company decided to invest in a new product line: a decision that would require significant capital.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"B","text":"The company decided, to invest in a new product line; a decision that would require significant capital.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"C","text":"The company decided, to invest in a new product line, a decision that would require significant capital.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"D","text":"The company decided to invest in a new product line, a decision that would require significant capital.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The phrase “a decision that would require significant capital” is a nonessential clause that modifies the noun phrase “a new product line.” Nonessential clauses are set off with commas.  Choice A is incorrect because the colon should not be used in this context. Choice B is incorrect because the semicolon should not be used in this context. Choice C is incorrect because the comma after “product line” should be a semicolon. Choice D is correct because it aligns with that evidence: The company decided to invest in a new product line, a decision that would require significant capit…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked. On the Digital SAT, the best explanation ties the correct answer to specific language in the stimulus rather than relying on outside knowledge alone.',
