UPDATE public.questions SET
  stimulus_text = 'An essay about the impact of social media on the modern world is expected to be structured logically. This ensures that the reader can follow the arguments and ideas presented in the essay. There are several ways to ensure that an essay is well-structured. For example, one technique is to use transition words to connect ideas and paragraphs. Transition words help the reader to understand the relationship between the different parts of the essay. However,  it is important to make sure that the transition words used are appropriate for the specific context and that they are used correctly.',
  question_text = 'Which choice best completes the text so that it conforms to the conventions of Standard English?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"They can help to clarify the meaning of an essay’s ideas, to help the reader to see how the essay’s ideas relate to one another.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"They can help to clarify the meaning of an essay’s ideas, helping the reader to see how the essay’s ideas relate to one another.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"They help to clarify the meaning of an essay’s ideas, to help the reader see how the essay’s ideas relate to one another.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"They help to clarify the meaning of an essay’s ideas, helping the reader see how the essay’s ideas relate to one another.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'Choice A uses parallel structure for clarity and conciseness. The phrases "to help the reader to see" and "to help the essay’s ideas relate to one another" have the same grammatical structure, which makes the sentence flow more smoothly and makes the meaning easier to understand. The other choices use a mix of finite and nonfinite verb forms, creating a disjointed sentence structure. The passage states that "An essay about the impact of social media on the modern world is expected to be structured logically. This ensures that …", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: They can help to clarify the meaning of an essay’s ideas, to help the reader to see how the essay’s …. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":1296,"opensat_domain":"Standard English Conventions","opensat_raw_id":"6435329d","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.917Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
